CREATE TABLE IF NOT EXISTS submission_documents(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),submission_id text NOT NULL,document_type varchar(50) NOT NULL,file_name varchar(255) NOT NULL,file_path text NOT NULL,file_size int,mime_type varchar(50),extracted_text text,data_extracted jsonb,virus_scan_status varchar(20) DEFAULT 'pending',review_status varchar(20) NOT NULL DEFAULT 'pending',reviewed_by varchar(100),reviewed_at timestamptz,review_notes text,uploaded_by varchar(100) NOT NULL,uploaded_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS underwriting_checklist(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),submission_id text NOT NULL,item_name varchar(255) NOT NULL,item_type varchar(50),is_required boolean DEFAULT true,is_completed boolean DEFAULT false,completed_at timestamptz,completed_by varchar(100),related_document_id text,notes text,display_order int DEFAULT 0,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS submission_notes(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),submission_id text NOT NULL,content text NOT NULL,note_type varchar(20),created_by varchar(100) NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),is_internal boolean DEFAULT true,visible_to_carrier boolean DEFAULT false);
